import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
// Assuming useAuth context might be used for actual registration,
// but for now, we'll just simulate success and navigate.
// import { useAuth } from "../../context/AuthContext"; 

function RegistrationPage() {
  const [name, setName] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isRegisterHovered, setIsRegisterHovered] = useState(false);
  const [activeInput, setActiveInput] = useState(null);
  const [showPassword, setShowPassword] = useState(false);
  const [isEyeHovered, setIsEyeHovered] = useState(false);
  const [isSignInLinkHovered, setIsSignInLinkHovered] = useState(false);

  // const { register } = useAuth(); // If you have a register function in your AuthContext
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API call for registration
    await new Promise(resolve => setTimeout(resolve, 1500));

    // In a real application, you would call your registration API here
    // try {
    //   await register({ name, companyName, email, password });
    //   navigate("/login"); // Navigate to login after successful registration
    // } catch (error) {
    //   console.error("Registration failed:", error);
    //   // Handle registration error (e.g., show error message)
    // }

    console.log("Registration successful for:", { name, companyName, email });
    navigate("/login"); // Navigate to login after simulated successful registration
    setIsLoading(false);
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  const isFormValid = name && companyName && email && password;

  // SVG Icons
  const EmailIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/>
      <polyline points="22,6 12,13 2,6"/>
    </svg>
  );

  const EyeIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
      <circle cx="12" cy="12" r="3"/>
    </svg>
  );

  const EyeOffIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/>
      <line x1="1" y1="1" x2="23" y2="23"/>
    </svg>
  );

  const LockIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
      <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
    </svg>
  );

  const UserIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
      <circle cx="12" cy="7" r="4"></circle>
    </svg>
  );

  const BuildingIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
      <line x1="12" y1="3" x2="12" y2="21"></line>
      <line x1="3" y1="9" x2="21" y2="9"></line>
      <line x1="3" y1="15" x2="21" y2="15"></line>
    </svg>
  );

  return (
    <div style={styles.container}>
      {/* Registration Card */}
      <div style={styles.card}>
        <div style={styles.cardGlow} />
        
        {/* Logo Section */}
        <div style={styles.logo}>
          <h1 style={styles.logoText}>FLOW TRACK</h1>
          {/* <p style={styles.tagline}>Modern Project Management Solution</p> */} {/* Removed tagline as per image */}
        </div>

        {/* <h2 style={styles.title}>Welcome User</h2> */} {/* Removed title as per image */}
        
        <form onSubmit={handleSubmit}>
          {/* Name Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Name</label>
            <div style={styles.inputContainer}>
              <input
                type="text"
                placeholder="Enter your name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                onFocus={() => setActiveInput('name')}
                onBlur={() => setActiveInput(null)}
                style={{
                  ...styles.input,
                  ...(activeInput === 'name' || name ? styles.inputFocus : {})
                }}
                required
              />
              <span style={styles.inputIcon}>
                <UserIcon />
              </span>
            </div>
          </div>

          {/* Company Name Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Company Name</label>
            <div style={styles.inputContainer}>
              <input
                type="text"
                placeholder="Enter your company name"
                value={companyName}
                onChange={(e) => setCompanyName(e.target.value)}
                onFocus={() => setActiveInput('companyName')}
                onBlur={() => setActiveInput(null)}
                style={{
                  ...styles.input,
                  ...(activeInput === 'companyName' || companyName ? styles.inputFocus : {})
                }}
                required
              />
              <span style={styles.inputIcon}>
                <BuildingIcon />
              </span>
            </div>
          </div>

          {/* Email Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email Address</label>
            <div style={styles.inputContainer}>
              <input
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                onFocus={() => setActiveInput('email')}
                onBlur={() => setActiveInput(null)}
                style={{
                  ...styles.input,
                  ...(activeInput === 'email' || email ? styles.inputFocus : {})
                }}
                required
              />
              <span style={styles.inputIcon}>
                <EmailIcon />
              </span>
            </div>
          </div>

          {/* Password Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <div style={styles.inputContainer}>
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                onFocus={() => setActiveInput('password')}
                onBlur={() => setActiveInput(null)}
                style={{
                  ...styles.input,
                  ...(activeInput === 'password' || password ? styles.inputFocus : {})
                }}
                required
              />
              <span style={styles.inputIcon}>
                <LockIcon />
              </span>
              <button
                type="button"
                style={{
                  ...styles.eyeIcon,
                  ...(isEyeHovered ? styles.eyeIconHover : {})
                }}
                onClick={togglePasswordVisibility}
                onMouseEnter={() => setIsEyeHovered(true)}
                onMouseLeave={() => setIsEyeHovered(false)}
                title={showPassword ? "Hide password" : "Show password"}
              >
                {showPassword ? <EyeOffIcon /> : <EyeIcon />}
              </button>
            </div>
          </div>

          {/* Submit Button */}
          <button 
            type="submit" 
            style={{
              ...styles.button,
              ...(isFormValid && !isLoading && isRegisterHovered ? styles.buttonHover : {}),
              ...(!isFormValid || isLoading ? styles.buttonDisabled : {})
            }}
            disabled={!isFormValid || isLoading}
            onMouseEnter={() => setIsRegisterHovered(true)}
            onMouseLeave={() => setIsRegisterHovered(false)}
          >
            {isLoading ? (
              <div style={styles.loadingSpinner}></div>
            ) : (
              <>
                Register
                <div style={{
                  ...styles.buttonGlow,
                  left: isRegisterHovered ? '100%' : '-100%'
                }} />
              </>
            )}
          </button>
        </form>

        {/* Footer */}
        <div style={styles.footer}>
          {/* <p style={styles.footerText}>
            Already have an account?{" "}
            <a 
              href="#" 
              onClick={() => navigate("/login")}
              style={{
                ...styles.link,
                ...(isSignInLinkHovered ? styles.linkHover : {})
              }}
              onMouseEnter={() => setIsSignInLinkHovered(true)}
              onMouseLeave={() => setIsSignInLinkHovered(false)}
            >
              Sign In
            </a>
          </p> */} {/* Removed "Already have an account?" as per image */}
          <p style={{ ...styles.footerText, marginTop: "10px" }}>
            © 2025 Vunathi Technologies Pvt Ltd
          </p>
        </div>
      </div>

      {/* CSS Animations */}
      <style>
        {`
          @keyframes slideUp {
            0% {
              opacity: 0;
              transform: translateY(30px);
            }
            100% {
              opacity: 1;
              transform: translateY(0);
            }
          }

          @keyframes fadeIn {
            0% {
              opacity: 0;
              transform: scale(0.9);
            }
            100% {
              opacity: 1;
              transform: scale(1);
            }
          }

          @keyframes glow {
            0%, 100% {
              opacity: 0.5;
            }
            50% {
              opacity: 1;
            }
          }

          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }

          /* General reset for input focus to ensure custom styles take precedence */
          input:focus {
            outline: none;
          }

          /* Applying styles from the image */
          body {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
          }
        `}
      </style>
    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    minHeight: "100vh",
    backgroundColor: "#2196F3", // Solid blue background from the image
    padding: "20px",
    fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
    position: "relative",
    overflow: "hidden"
  },
  card: {
    backgroundColor: "#E0F2F7", // Light blue card background from the image
    padding: "50px 40px",
    borderRadius: "20px",
    boxShadow: `0 25px 50px -12px rgba(0, 0, 0, 0.2)`, // Adjusted shadow
    width: "100%",
    maxWidth: "420px",
    border: "none", // No border as in the image
    position: "relative",
    zIndex: 10,
    animation: "slideUp 0.8s ease-out"
  },
  cardGlow: { // Keeping glow but it might not be visible with solid background
    position: "absolute",
    top: 0,
    left: 0,
    right: 0,
    height: "1px",
    background: "linear-gradient(90deg, transparent, #3B82F6, transparent)",
    animation: "glow 3s ease-in-out infinite"
  },
  logo: {
    textAlign: "center",
    marginBottom: "40px", // Increased margin for spacing as per image
    animation: "fadeIn 1s ease-out"
  },
  logoText: {
    fontSize: "42px",
    fontWeight: "800",
    color: "#333", // Darker text for Flow Track from the image
    margin: "0",
    letterSpacing: "-0.02em"
  },
  tagline: { // Retaining style but commented out usage as per image
    textAlign: "center",
    color: "#666", 
    fontSize: "14px",
    marginTop: "8px",
    fontWeight: "400",
    letterSpacing: "0.02em"
  },
  title: { // Retaining style but commented out usage as per image
    textAlign: "center",
    marginBottom: "35px",
    fontSize: "28px",
    fontWeight: "700",
    color: "#333",
    marginTop: "0"
  },
  inputGroup: {
    marginBottom: "25px",
    position: "relative"
  },
  label: {
    display: "block",
    marginBottom: "8px",
    fontSize: "14px",
    fontWeight: "600",
    color: "#333", // Darker label text from the image
    transition: "all 0.3s ease"
  },
  inputContainer: {
    position: "relative",
    transition: "all 0.3s ease"
  },
  input: {
    width: "100%",
    padding: "16px 50px 16px 20px",
    borderRadius: "12px",
    border: "1px solid #ccc", // Light gray border from the image
    fontSize: "15px",
    color: "#333", // Darker text for input from the image
    backgroundColor: "#fff", // White background from the image
    transition: "all 0.3s ease",
    boxSizing: "border-box",
    fontFamily: "inherit"
  },
  inputFocus: {
    borderColor: "#2196F3", // Blue border on focus
    boxShadow: "0 0 0 3px rgba(33, 150, 243, 0.3)", // Blue shadow on focus
    transform: "none" // No transform on focus as in the image
  },
  inputIcon: {
    position: "absolute",
    right: "15px",
    top: "50%",
    transform: "translateY(-50%)",
    color: "#666", // Darker icon color from the image
    transition: "all 0.3s ease",
    fontSize: "18px",
    width: "20px",
    height: "20px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center"
  },
  eyeIcon: {
    position: "absolute",
    right: "15px",
    top: "50%",
    transform: "translateY(-50%)",
    color: "#666", // Darker icon color
    transition: "all 0.3s ease",
    cursor: "pointer",
    fontSize: "18px",
    background: "none",
    border: "none",
    padding: "5px",
    borderRadius: "4px",
    width: "20px",
    height: "20px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center"
  },
  eyeIconHover: {
    backgroundColor: "rgba(0, 0, 0, 0.05)", // Slightly darker background on hover
    color: "#2196F3" // Blue on hover
  },
  button: {
    width: "100%",
    padding: "16px",
    border: "none",
    borderRadius: "12px",
    backgroundColor: "#3F51B5", // Solid blue button from the image
    color: "#FFFFFF",
    fontWeight: "600",
    fontSize: "15px",
    cursor: "pointer",
    transition: "all 0.3s ease",
    position: "relative",
    overflow: "hidden",
    boxShadow: "0 4px 15px rgba(63, 81, 181, 0.3)" // Shadow adjusted to button color
  },
  buttonHover: {
    transform: "translateY(-3px)",
    boxShadow: "0 8px 25px rgba(63, 81, 181, 0.4)" // Shadow adjusted to button color
  },
  buttonDisabled: {
    opacity: "0.6",
    cursor: "not-allowed",
    transform: "none"
  },
  buttonGlow: {
    position: "absolute",
    top: "0",
    left: "-100%",
    width: "100%",
    height: "100%",
    background: "linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)",
    transition: "left 0.5s ease"
  },
  loadingSpinner: {
    width: "20px",
    height: "20px",
    border: "2px solid rgba(255,255,255,0.3)",
    borderTop: "2px solid #FFFFFF",
    borderRadius: "50%",
    animation: "spin 1s linear infinite",
    margin: "0 auto"
  },
  footer: {
    textAlign: "center",
    marginTop: "30px",
    paddingTop: "25px",
    borderTop: "1px solid #ccc" // Light gray border from the image
  },
  footerText: {
    color: "#666", // Darker text from the image
    fontSize: "12px",
    margin: "0"
  },
  link: {
    color: "#3F51B5", // Blue link color from the image
    textDecoration: "none",
    fontWeight: "500",
    transition: "all 0.3s ease",
    position: "relative"
  },
  linkHover: {
    color: "#2196F3" // Lighter blue on hover
  }
};

export default RegistrationPage;
